    v_prime.value == v.value + 1
}

spec fn decrement_op(v: Variables, v_prime: Variables) -> bool {
    v_prime.value == v.value - 1
}

enum Step {
    Increment,
    Decrement,
}

spec fn next_step(v: Variables, v_prime: Variables, step: Step) -> bool {
